import time
import random
from typing import Callable, Any, List, Optional

random.seed(42)


class CircuitBreaker:
    """Circuit breaker pattern for API calls."""

    def __init__(self, failure_threshold: int = 5, recovery_timeout: float = 30.0):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self._failure_count = 0
        self._state = "closed"
        self._last_failure_time = 0.0

    @property
    def state(self) -> str:
        """Return current state: 'closed', 'open', or 'half_open'."""
        if self._state == "open":
            if time.time() - self._last_failure_time >= self.recovery_timeout:
                return "half_open"
        return self._state

    def allow_request(self) -> bool:
        """Return True if request should be attempted."""
        current_state = self.state
        return current_state in ("closed", "half_open")

    def record_success(self) -> None:
        """Record successful call."""
        self._failure_count = 0
        self._state = "closed"

    def record_failure(self) -> None:
        """Record failed call."""
        self._failure_count += 1
        self._last_failure_time = time.time()
        if self._failure_count >= self.failure_threshold:
            self._state = "open"


class RetryEngine:
    """Retry engine with exponential backoff and circuit breaker."""

    def __init__(
        self,
        max_retries: int = 3,
        base_delay: float = 1.0,
        max_delay: float = 60.0,
        circuit_breaker: Optional[CircuitBreaker] = None,
    ):
        self.max_retries = max_retries
        self.base_delay = base_delay
        self.max_delay = max_delay
        self.circuit_breaker = circuit_breaker

    def compute_delay(self, attempt: int) -> float:
        """Compute backoff delay with full jitter."""
        max_for_attempt = min(self.max_delay, self.base_delay * (2 ** attempt))
        return random.uniform(0, max_for_attempt)

    def execute(self, func: Callable) -> dict:
        """
        Execute func with retry logic.
        """
        errors: List[str] = []
        attempts = 0

        # Check circuit breaker before starting
        if self.circuit_breaker and not self.circuit_breaker.allow_request():
            return {
                "success": False,
                "result": None,
                "attempts": 0,
                "errors": ["Circuit breaker is open"],
            }

        for attempt in range(self.max_retries + 1):
            attempts += 1
            try:
                result = func()
                if self.circuit_breaker:
                    self.circuit_breaker.record_success()
                return {
                    "success": True,
                    "result": result,
                    "attempts": attempts,
                    "errors": errors,
                }
            except Exception as e:
                errors.append(str(e))
                if self.circuit_breaker:
                    self.circuit_breaker.record_failure()

                if attempt < self.max_retries:
                    # Compute delay (don't actually sleep in tests)
                    delay = self.compute_delay(attempt)

        return {
            "success": False,
            "result": None,
            "attempts": attempts,
            "errors": errors,
        }
